The most effective way to render a 3D model in a web browser is using **Three.js**. Below is a complete, single-file HTML solution.

This code procedurally generates a "Low Poly" house (a cube for the body and a pyramid for the roof) using geometric primitives. It includes lighting, shadows, and a camera controller so you can rotate around the model.

### How to use this:
1.  Copy the code below.
2.  Save it as an `.html` file (e.g., `house.html`).
3.  Open that file in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Left Click: Rotate | Right Click: Pan | Scroll: Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 8);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        renderer.shadowMap.type = THREE.PCFSoftShadowMap;
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 1, 0);

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. MATERIALS
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513, roughness: 0.8 });
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.5 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x88ccff, emissive: 0x88ccff, emissiveIntensity: 0.2 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. BUILDING THE HOUSE
        const houseGroup = new THREE.Group();

        // A. The Floor (Ground)
        const floorGeometry = new THREE.PlaneGeometry(100, 100);
        const floor = new THREE.Mesh(floorGeometry, grassMaterial);
        floor.rotation.x = -Math.PI / 2;
        floor.receiveShadow = true;
        scene.add(floor);

        // B. The House Body (Cube)
        const bodyGeometry = new THREE.BoxGeometry(4, 3, 4);
        const body = new THREE.Mesh(bodyGeometry, wallMaterial);
        body.position.y = 1.5;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // C. The Roof (Pyramid)
        const roofGeometry = new THREE.ConeGeometry(3.5, 2, 4);
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 4; // Sit on top of the body
        roof.rotation.y = Math.PI / 4; // Rotate to align with cube
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // D. Windows
        const windowGeo = new THREE.BoxGeometry(1, 1, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(0.8, 2, 2.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(-0.8, 2, 2.1);
        houseGroup.add(win2);

        // Side Window
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(0.8, 2, -1.9);
        houseGroup.add(win3);

        // E. Door
        const doorGeo = new THREE.BoxGeometry(1.2, 2.2, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.1, 2.1);
        houseGroup.add(door);

        // F. Chimney
        const chimneyGeo = new THREE.BoxGeometry(0.6, 1.5, 0.6);
        const chimney = new THREE.Mesh(chimneyGeo, roofMaterial);
        chimney.position.set(1.5, 4.5, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Key Features of this Code:
*   **Procedural Generation:** It builds the house using basic shapes (Box, Cone, Plane) rather than loading an external file. This ensures it works instantly without needing to download assets.
*   **Lighting & Shadows:** It uses a `DirectionalLight` to simulate the sun, casting realistic shadows on the ground and the house itself.
*   **Interactivity:** It uses `OrbitControls`, allowing you to click and drag to rotate the view, scroll to zoom, and right-click to pan.
*   **Materials:** It uses `MeshStandardMaterial` which reacts to light, giving the house a 3D feel rather than a flat look.

### How to load a real 3D file (GLTF/OBJ)
If you have a specific 3D model file (like a `.glb` or `.gltf` file) and want to load that instead of the procedural house, you would replace the "BUILDING THE HOUSE" section with the `GLTFLoader`.

Here is the snippet you would add to load a file:

```javascript
import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';

const loader = new GLTFLoader();
loader.load('path/to/your/model.glb', function (gltf) {
    const model = gltf.scene;
    model.traverse((child) => {
        if (child.isMesh) {
            child.castShadow = true;
            child.receiveShadow = true;
        }
    });
    scene.add(model);
}, undefined, function (error) {
    console.error(error);
});
```
